sub_queries.sql:
SELECT Pos, Driver, Car_Constructor, Time_Diff_Status 
FROM T89 
WHERE LOWER(Driver) LIKE LOWER('%prince bira%');

SELECT AVG(CAST(Points AS REAL)) AS Average_Points
FROM T83
WHERE Rank = 1;

SELECT Nationality 
FROM T5 
WHERE Rank <= 5;

SELECT Nationality, AVG(CAST(REPLACE(REPLACE(Time, ':', '.'), '.', '') AS REAL)) AS Average_Time
FROM T5
GROUP BY Nationality;
